// ═══════════════════════════════════════════════════════════════
// RELANCE SERVICE JURIDIQUE — Factures non traitées (délai 7j dépassé)
// Entrée attendue : fusion (Merge/Append) de deux sources :
//   1) Factures en retard : { numero_facture, numero_dff, premier_envoi,
//      dernier_envoi, nb_envois, nb_envois_max, created_at }
//   2) Destinataire(s) : { code_baallah, nom_baallah, prenom_baallah,
//      email_baallah, telephone_baallah }
// ═══════════════════════════════════════════════════════════════

const DELAI_JOURS = 7; // niveau d'escalade géré par ce node

const allItems = $input.all();

// ── EXTRACTION ROBUSTE : sépare factures / destinataires ──────────
function extraireItems(allItems) {
  const factures = [];
  const destinataires = [];
  for (const item of allItems) {
    const val = item.json;
    if (val && val.code_baallah) {
      destinataires.push(val);
    } else if (val && val.numero_facture) {
      factures.push(val);
    }
  }
  return { factures, destinataires };
}

const { factures, destinataires } = extraireItems(allItems);

if (factures.length === 0) {
  return []; // rien à relancer
}

const fmtDate = (d) => {
  if (!d) return '—';
  const dt = new Date(d.replace(' ', 'T'));
  return dt.toLocaleString('fr-FR', {
    day: '2-digit', month: '2-digit', year: 'numeric',
    hour: '2-digit', minute: '2-digit'
  });
};

const joursEcoules = (d) => {
  if (!d) return null;
  const dt = new Date(d.replace(' ', 'T'));
  const diffMs = Date.now() - dt.getTime();
  return Math.floor(diffMs / (1000 * 60 * 60 * 24));
};

const badgeRelance = (nb, nbMax) => {
  const ratio = nb - nbMax;
  if (ratio >= 2)
    return `<span style="background:#fadbd8;color:#922b21;padding:2px 9px;border-radius:10px;font-size:12px;font-weight:700;">🔴 ${nb}× envoyés</span>`;
  if (ratio >= 1)
    return `<span style="background:#fdebd0;color:#784212;padding:2px 9px;border-radius:10px;font-size:12px;font-weight:700;">🟠 ${nb}× envoyés</span>`;
  return `<span style="background:#fef9e7;color:#9a7d0a;padding:2px 9px;border-radius:10px;font-size:12px;font-weight:700;">🟡 ${nb}× envoyés</span>`;
};

const badgeJours = (j) => {
  if (j === null) return '—';
  if (j >= 14)
    return `<span style="color:#922b21;font-weight:700;">${j} j</span>`;
  if (j >= 7)
    return `<span style="color:#c0392b;font-weight:700;">${j} j</span>`;
  return `<span style="color:#7d6608;font-weight:600;">${j} j</span>`;
};

// ── TABLEAU DES FACTURES ────────────────────────────────────────
const lignesTableHTML = factures.map((f, i) => {
  const jours = joursEcoules(f.premier_envoi);
  return `
    <tr style="background:${i % 2 === 0 ? '#fff' : '#fafafa'};">
      <td style="padding:8px 10px;border-bottom:1px solid #eee;font-weight:700;font-size:13px;color:#1a5276;">${f.numero_facture}</td>
      <td style="padding:8px 10px;border-bottom:1px solid #eee;font-size:12px;color:#555;">${f.numero_dff || '—'}</td>
      <td style="padding:8px 10px;border-bottom:1px solid #eee;font-size:12px;">${fmtDate(f.premier_envoi)}</td>
      <td style="padding:8px 10px;border-bottom:1px solid #eee;font-size:12px;">${fmtDate(f.dernier_envoi)}</td>
      <td style="padding:8px 10px;border-bottom:1px solid #eee;text-align:center;">${badgeRelance(f.nb_envois)}</td>
    </tr>`;
}).join('');

const nbFactures = factures.length;
const nbCritiques = factures.filter(f => (f.nb_envois - f.nb_envois_max) >= 2).length;

// ── GÉNÉRATION D'UN MESSAGE PAR DESTINATAIRE ────────────────────
const result = [];

const listeDestinataires = destinataires.length > 0
  ? destinataires
  : [{ nom_baallah: '', prenom_baallah: '', email_baallah: null }]; // fallback si non fourni

for (const dest of listeDestinataires) {
  const nomComplet = `${dest.prenom_baallah || ''} ${dest.nom_baallah || ''}`.trim() || 'Responsable';

  const htmlMessage = `
<div style="font-family:'Segoe UI',Tahoma,Geneva,Verdana,sans-serif;max-width:760px;margin:auto;border:1px solid #d5d8dc;border-radius:10px;overflow:hidden;">

  <div style="background:linear-gradient(135deg,#922b21 0%,#c0392b 100%);padding:26px 30px;text-align:center;">
    <p style="color:#fadbd8;margin:0 0 4px;font-size:11px;letter-spacing:2px;text-transform:uppercase;">Relance Service Juridique</p>
    <h2 style="color:#fff;margin:0;font-size:20px;font-weight:700;">⚠ FACTURES EN ATTENTE DE TRAITEMENT — DÉLAI ${DELAI_JOURS}J DÉPASSÉ</h2>
    <p style="color:rgba(255,255,255,0.85);margin:6px 0 0;font-size:13px;">
      ${nbFactures} facture(s) concernée(s)${nbCritiques > 0 ? ` — dont ${nbCritiques} en relance critique` : ''}
    </p>
  </div>

  <div style="padding:26px 30px;">

    <p style="font-size:14px;color:#333;">Bonjour ${nomComplet},</p>
    <p style="font-size:14px;color:#333;line-height:1.6;">
      Les factures listées ci-dessous ont dépassé un délai de <strong>${DELAI_JOURS} jours</strong> depuis leur première
      notification et n'ont, à ce jour, toujours pas été traitées. Elles ont fait l'objet de plusieurs relances
      automatiques sans retour. Merci de bien vouloir statuer sur leur traitement.
    </p>

    <h3 style="color:#1a5276;border-bottom:2px solid #2e86c1;padding-bottom:7px;margin-top:22px;">
      📄 Factures concernées (${nbFactures})
    </h3>
    <div style="overflow-x:auto;">
    <table style="width:100%;border-collapse:collapse;font-size:12px;border:1px solid #d5d8dc;border-radius:6px;overflow:hidden;">
      <thead>
        <tr style="background:#2c3e50;color:white;">
          <th style="padding:8px 10px;text-align:left;">N° Facture</th>
          <th style="padding:8px 10px;text-align:left;">N° DFF</th>
          <th style="padding:8px 10px;text-align:left;">1ère notification</th>
          <th style="padding:8px 10px;text-align:left;">Dernière notification</th>
          <th style="padding:8px 10px;text-align:center;">Relances</th>
        </tr>
      </thead>
      <tbody>${lignesTableHTML}</tbody>
    </table>
    </div>

    <div style="background:#fff3cd;border-left:5px solid #e74c3c;padding:16px 20px;border-radius:4px;margin-top:24px;">
      <p style="margin:0 0 8px;font-weight:700;color:#c0392b;font-size:15px;">🔴 ACTION REQUISE</p>
      <p style="margin:0;color:#333;font-size:14px;line-height:1.6;">
        Merci de traiter ces dossiers dans les meilleurs délais afin d'éviter tout blocage administratif
        ou comptable supplémentaire.
      </p>
    </div>

  </div>

  <div style="background:#f2f3f4;padding:12px 20px;text-align:center;font-size:11px;color:#aaa;border-top:1px solid #e0e0e0;">
    Message généré automatiquement — Système de suivi des relances factures &nbsp;|&nbsp; Jbel Annour
    &nbsp;|&nbsp; ${new Date().toLocaleString('fr-FR')}
  </div>
</div>`.trim();

  result.push({
    json: {
      to: dest.email_baallah || '',
      subject: `⚠ RELANCE JURIDIQUE — ${nbFactures} facture(s) en attente (délai ${DELAI_JOURS}j dépassé)`,
      message: htmlMessage,
      meta: {
        destinataire: nomComplet,
        email: dest.email_baallah,
        nb_factures: nbFactures,
        nb_critiques: nbCritiques,
        factures: factures.map(f => f.numero_facture),
        delai_jours: DELAI_JOURS
      }
    }
  });
}

return result;

// ═══════════════════════════════════════════════════════════════
