      <td style="padding:8px 10px;border-bottom:1px solid #eee;font-weight:700;font-size:13px;color:#1a5276;">${f.numero_facture}</td>
      <td style="padding:8px 10px;border-bottom:1px solid #eee;font-size:12px;color:#555;">${f.numero_dff || '—'}</td>
